mapper.select:
/* selectWmt10List */
select concat(W.COMPKEY , W.STOCKKY) as rowkey , W.COMPKEY as compkey , W.STOCKKY as stockky , W.WAREKEY as warekey , '500' as doccate , '560' as doctype , W.TRUNTYP as truntyp , W.TRUNPID as trunpid , W.LOTNMKY as lotnmky , W.OWNERKY as ownerky , W.SKUMKEY as skumkey , M.SKUDESC as skudesc , W.VENDKEY as vendkey , W.AREAKEY as areakey , W.ZONEKEY as zonekey , W.LOCAKEY as locakey , W.SIRBCOD as sirbcod , W.STOTQTY as stotqty , '' as toareky , '' as tozonky , '' as tolocky , 0 as fordqty , '' as parsncd , '' as parsnnm , fn_com_todate(W.PRODDAT) as proddat , W.SHELIFE as shelife , fn_com_todate(W.EXPIDAT) as expidat , W.RCVDCDT as rcvdcdt , W.RCVFRDT as rcvfrdt , W.LOTFRKY as lotfrky , W.LOTAT01 as lotat01 , W.LOTAT02 as lotat02 , W.LOTAT03 as lotat03 , W.LOTAT04 as lotat04 , W.LOTAT05 as lotat05 , W.LOTAT06 as lotat06 , W.LOTAT07 as lotat07 , W.LOTAT08 as lotat08 , W.LOTAT09 as lotat09 , W.LOTAT10 as lotat10 , W.LOTAT11 as lotat11 , W.LOTAT12 as lotat12 , W.LOTAT13 as lotat13 , W.LOTAT14 as lotat14 , W.LOTAT15 as lotat15 , W.LOTAT16 as lotat16 , W.LOTAT17 as lotat17 , W.LOTAT18 as lotat18 , W.LOTAT19 as lotat19 , W.LOTAT20 as lotat20 , W.STKSTAT as stkstat , W.BLOCKID as blockid , W.SALLQTY as sallqty , W.SINBQTY as sinbqty , W.SOUBQTY as soubqty , W.SBLOQTY as sbloqty , W.SUOMKEY as suomkey , fn_com_todate(W.CREDATE) as credate , fn_com_totime(W.CRETIME) as CRETIME , fn_sy_usernam(W.COMPKEY , W.CREUSER) as creuser , fn_com_todate(W.LMODATE) as lmodate , fn_com_totime(W.LMOTIME) as LMOTIME , fn_sy_usernam(W.COMPKEY , W.LMOUSER) as lmouser , W.RCVDCDT as rcvdcdt , W.RCVFRDT as rcvfrdt , W.LOTFRKY as lotfrky , W.INDIBZL as indibzl , W.INDIARC as indiarc , W.UPDTCHK as updtchk from WSTKKY W inner join MSKUWC M on M.COMPKEY = W.COMPKEY and M.WAREKEY = W.WAREKEY and M.OWNERKY = W.OWNERKY and M.SKUMKEY = W.SKUMKEY left outer join SUSRMA U on U.COMPKEY = W.COMPKEY and U.USERACT = M.SKUAT01 where 1=1 and W.COMPKEY = #{userData.compkey}
and W.WAREKEY = #{warekey}
and W.OWNERKY = #{ownerky}
and W.SKUMKEY like concat('%' , #{skumkey} , '%')
and M.SKUDESC like concat('%' , #{skudesc} , '%')
and W.AREAKEY NOT IN ('SYS', 'SHP')
and W.STOTQTY > 0 and W.SALLQTY = 0 and W.SOUBQTY = 0 and W.SBLOQTY = 0 order by M.SKUDESC asc

/* selectWareAreaZoneRelations */
select MWA.WAREKEY as WAREKEY, MAR.AREAKEY as AREAKEY, MZO.ZONEKEY as ZONEKEY,
MAR.AREANAM as AREANAM, MZO.ZONENAM as ZONENAM,
MZO.ZONEKEY as TOZONKY
from MWARMA MWA
inner join MAREMA MAR on (MWA.WAREKEY = MAR.WAREKEY and MWA.COMPKEY = MAR.COMPKEY)
inner join MZONMA MZO on (MWA.WAREKEY = MZO.WAREKEY and MAR.AREAKEY = MZO.AREAKEY and MWA.COMPKEY = MZO.COMPKEY)
where MWA.COMPKEY = #{userData.compkey}
and MWA.WHUSEYN = 'Y' and MAR.ARUSEYN = 'Y' and MZO.ZOUSEYN = 'Y'

	and MWA.WAREKEY = #{warekey}


	and MAR.AREAKEY = #{areakey}


	and MZO.ZONEKEY = #{zonekey}

group by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY
order by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY

	 /* updateWtakitList */
	 CALL sp_wm_ctrstokky( #{userData.compkey}, #{warekey}, #{doccate} , #{doctype}, #{taskoky} , #{taskoit}, #{userData.useract}
         , #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

/* selectWmt11List */
select concat(A.COMPKEY , A.TASKOKY) as rowkey , A.COMPKEY as compkey , A.TASKOKY as taskoky , A.TASKOIT as taskoit , A.WAREKEY as warekey , A.DOCCATE as doccate , A.DOCTYPE as doctype , A.OWNERKY as ownerky , A.STKSTAT as stkstat , A.SKUMKEY as skumkey , m.SKUDESC as skudesc , A.FRAREKY as frareky , A.FRZONKY as frzonky , A.FRLOCKY as frlocky , A.FORDQTY as fordqty , A.FUOMEKY as fuomeky , A.TOAREKY as toareky , A.TOZONKY as tozonky , A.TOLOCKY as tolocky , A.FORDQTY as tcmpqty , fn_com_todate(A.EXPIDAT) as expidat , A.PKRSNCD as pkrsncd , A.PKRSNNM as pkrsnnm , fn_com_todate(A.CREDATE) as credate , fn_com_totime(A.CRETIME) as cretime , fn_sy_usernam(A.COMPKEY , A.CREUSER) as creuser , fn_com_todate(A.LMODATE) as lmodate , fn_com_totime(A.LMOTIME) as lmotime , fn_sy_usernam(A.COMPKEY , A.LMOUSER) as lmouser , A.INDIBZL as indibzl , A.INDIARC as indiarc , 0 as updtchk from WTAKIT A inner join MSKUWC m on m.compkey = A.COMPKEY and m.WAREKEY = A.WAREKEY and m.OWNERKY = A.OWNERKY and m.SKUMKEY = A.SKUMKEY where 1=1 and A.COMPKEY = #{userData.compkey} and A.TASKSTS = 'TASK' and A.DOCTYPE = '560'
and A.WAREKEY = #{warekey}
and A.OWNERKY = #{ownerky}
and A.DOCTYPE = #{doctype}
and A.SKUMKEY like concat('%' , #{skumkey} , '%')
and m.SKUDESC like concat('%' , #{skudesc} , '%')
and A.TASKOKY like concat('%' , #{taskoky} , '%')
order by TASKOKY , TASKOIT

mapper.update:
/* updateWmt11List */

update WTAKIT
 set TCMPQTY = #{tcmpqty}
  ,	 LMODATE = to_char(now() , 'YYYYMMDD') 
  ,  LMOTIME = to_char(now() , 'hh24miss') 
  ,  LMOUSER = #{userData.useract}
 where 1=1
  and COMPKEY = #{userData.compkey} 
  and TASKOKY = #{taskoky}
  and TASKOIT = #{taskoit}

update WTAKIT
 set PKRSNCD = #{pkrsncd}
  ,  PKRSNNM = #{pkrsnnm}
  ,	 LMODATE = to_char(now() , 'YYYYMMDD') 
  ,  LMOTIME = to_char(now() , 'hh24miss') 
  ,  LMOUSER = #{userData.useract}
 where 1=1
  and COMPKEY = #{userData.compkey}
  and TASKOKY = #{taskoky}
  and TASKOIT = #{taskoit}

mapper.select:
	 /* updateWtakitCancelList */
	 CALL sp_wm_ctrstokky_cancel( #{userData.compkey}, #{warekey}, #{doccate} , #{doctype}, #{taskoky} , #{taskoit}, #{userData.useract}
         , #{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=INTEGER} )

select concat(WS.COMPKEY , WS.TASKOKY) as rowkey , WS.COMPKEY, WS.TASKOKY, WS.TASKOIT, WS.WAREKEY, WS.OWNERKY , WS.FORDQTY, WS.SKUMKEY, WS.SKUDESC, WS.DOCCATE, WS.DOCTYPE, ( select DOCTYNM from MDOCMA MD where MD.COMPKEY = WS.COMPKEY and MD.WAREKEY = WS.WAREKEY and MD.DOCCATE = WS.DOCCATE and MD.DOCTYPE = WS.DOCTYPE ) as doctynm , ( select OWNAMLC from MOWRMA MO where MO.COMPKEY = WS.COMPKEY and MO.OWNERKY = WS.OWNERKY ) as ownamlc , IFNULL(TWT.STOTQTY, 0) AS stotqty, IFNULL(SWT.STOTQTY, 0) AS ltotqty, IFNULL(MIN(round(PWS.STOTQTY / PWS.SBSTQTY)), 0) AS psbtqty, CASE WHEN IFNULL(MIN(round(PWS.STOTQTY / PWS.SBSTQTY)), 0) > WS.FORDQTY THEN WS.FORDQTY ELSE IFNULL(MIN(round(PWS.STOTQTY / PWS.SBSTQTY)), 0) END AS tcmpqty from WTAKIT WS left outer join ( select WST.COMPKEY, WST.WAREKEY, WST.OWNERKY, WST.SKUMKEY, SUM(WST.STOTQTY) - SUM(WST.SBLOQTY) AS STOTQTY from WSTKKY WST where WST.COMPKEY = #{userData.compkey} and WST.WAREKEY = #{warekey}
and WST.OWNERKY = #{ownerky}
and WST.AREAKEY in ('STG' , 'TAK') and WST.STOTQTY > 0 group by WST.COMPKEY, WST.WAREKEY, WST.OWNERKY, WST.SKUMKEY ) TWT on WS.COMPKEY = TWT.COMPKEY and WS.WAREKEY = TWT.WAREKEY and WS.OWNERKY = TWT.OWNERKY and WS.SKUMKEY = TWT.SKUMKEY left outer join ( select COMPKEY, WAREKEY, OWNERKY, SKUMKEY, SUM(STOTQTY) - SUM(SBLOQTY) AS STOTQTY from WSTKKY
COMPKEY = #{userData.compkey} and WAREKEY = #{warekey}
and OWNERKY = #{ownerky}
and AREAKEY = 'TAK' and ZONEKEY = 'SETZ' and STOTQTY > 0 group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY
) SWT on WS.COMPKEY = SWT.COMPKEY and WS.WAREKEY = SWT.WAREKEY and WS.OWNERKY = SWT.OWNERKY and WS.SKUMKEY = SWT.SKUMKEY left outer join ( select MST.COMPKEY, MST.WAREKEY, MST.OWNERKY, MST.SKUMKEY, MST.SBSTQTY, SUM(WS.STOTQTY) - SUM(WS.SBLOQTY) AS STOTQTY , MIN(round(WS.STOTQTY / MST.SBSTQTY)) AS PSBTQTY from MSKUST MST inner join WSTKKY WS on WS.COMPKEY = MST.COMPKEY and WS.OWNERKY = MST.OWNERKY and WS.SKUMKEY = MST.SBSKUKY and WS.AREAKEY = 'TAK' and WS.ZONEKEY = 'SETZ' group by MST.COMPKEY , MST.WAREKEY , MST.OWNERKY , MST.SKUMKEY , MST.SBSKUKY ) PWS on WS.COMPKEY = PWS.COMPKEY and WS.WAREKEY = PWS.WAREKEY and WS.OWNERKY = PWS.OWNERKY and WS.SKUMKEY = PWS.SKUMKEY
WS.COMPKEY = #{userData.compkey} and WS.WAREKEY = #{warekey} and WS.DOCCATE = '500' and WS.DOCTYPE = '550'
and WS.OWNERKY = #{ownerky}
and WS.TASKSTS = #{tasksts}
and WS.TASKOKY = #{taskoky}
and WS.SKUMKEY = #{skumkey}
and WS.SKUDESC = #{skudesc}
group by WS.TASKOKY , WS.TASKOIT , WS.SKUMKEY

mapper.update:
update WTAKIT
   set TCMPQTY = #{tcmpqty}
     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
     , LMOUSER = #{userData.useract}
 where COMPKEY = #{compkey}
   and TASKOKY = #{taskoky}
   and TASKOIT = #{taskoit}

update.foreach:
	update WTAKIT
 	   set TASKSTS = 'TSCANCEL'
 	     , FORDQTY = 0 
	     , LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
	     , LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
	     , LMOUSER = #{item.userData.useract}
	 where COMPKEY = #{item.compkey}
	   and TASKOKY = #{item.taskoky} 
	   and TASKOIT = #{item.taskoit} 
	   and SKUMKEY = #{item.skumkey}

mapper.select:
select concat(WST.COMPKEY , WST.STOCKKY) as rowkey , WST.COMPKEY , WST.WAREKEY , WST.OWNERKY , ( select OWNAMLC from MOWRMA MO where MO.COMPKEY = WST.COMPKEY and MO.OWNERKY = WST.OWNERKY ) as ownamlc , WST.SKUMKEY , WST.SKUDESC , WST.STOTQTY as ltotqty, SUM(IFNULL(WTA.FORDQTY, 0)) as tordqty from WSTKKY WST inner join MSKUWC MSK on MSK.COMPKEY = WST.COMPKEY and MSK.WAREKEY = WST.WAREKEY and MSK.OWNERKY = WST.OWNERKY and MSK.SKUMKEY = WST.SKUMKEY and MSK.SKUTYPE = 'SET' left outer join WTAKIT WTA on WTA.COMPKEY = WST.COMPKEY and WTA.WAREKEY = WST.WAREKEY and WTA.OWNERKY = WST.OWNERKY and WTA.SKUMKEY = WST.SKUMKEY and WTA.DOCCATE = '500' and WTA.DOCTYPE = '551' and WTA.TASKSTS = 'NEW'
WST.COMPKEY = #{userData.compkey} and WST.WAREKEY = #{warekey} and WST.AREAKEY = 'TAK' and WST.ZONEKEY = 'SETZ' and WST.STOTQTY > 0
and WST.OWNERKY = #{ownerky}
and WST.SKUMKEY = #{skumkey}
and WST.SKUDESC = #{skudesc}
and MST.SBSKUKY = #{sbskuky}
group by WST.COMPKEY , WST.WAREKEY , WST.OWNERKY , WST.SKUMKEY

select concat(WS.COMPKEY , WS.TASKOKY) as rowkey , WS.COMPKEY, WS.TASKOKY, WS.TASKOIT, WS.WAREKEY, WS.OWNERKY , WS.FORDQTY, WS.FORDQTY as tcmpqty , WS.SKUMKEY, WS.SKUDESC, WS.DOCCATE, WS.DOCTYPE, ( select DOCTYNM from MDOCMA MO where MO.COMPKEY = WS.COMPKEY and MO.WAREKEY = WS.WAREKEY and MO.DOCCATE = WS.DOCCATE and MO.DOCTYPE = WS.DOCTYPE ) as doctynm , SWT.STOTQTY from WTAKIT WS left outer join ( select COMPKEY, WAREKEY, OWNERKY, SKUMKEY, SUM(STOTQTY) - SUM(SBLOQTY) AS STOTQTY from WSTKKY
COMPKEY = #{userData.compkey} and WAREKEY = #{warekey}
and OWNERKY = #{ownerky}
and AREAKEY = 'TAK' and ZONEKEY = 'SETZ' and STOTQTY > 0 group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY
) SWT on WS.COMPKEY = SWT.COMPKEY and WS.WAREKEY = SWT.WAREKEY and WS.OWNERKY = SWT.OWNERKY and WS.SKUMKEY = SWT.SKUMKEY
WS.COMPKEY = #{userData.compkey} and WS.WAREKEY = #{warekey} and WS.DOCCATE = '500' and WS.DOCTYPE = '551' and WS.TASKSTS = 'NEW'
and WS.OWNERKY = #{ownerky}
and WS.TASKOKY = #{taskoky}
and WS.SKUMKEY = #{skumkey}
and WS.SKUDESC = #{skudesc}
